script.text:

function setObjectForm&Controller;Hidden(f, c, l, t, v) {
  var a = c.split(','), b = (t.indexOf(v) > -1);
  for (var i = 0; i < a.length; i++) {
    var name = $func.trim(a[i]), o = f.getItem(name);
    if (l) {
      o.field.AllowNulls = !b;
      if (b) {
        var grandNode = o.parentNode.parentNode;
        Sys.UI.DomElement.addCssClass(grandNode, 'Required');
        Sys.UI.DomElement.addCssClass(grandNode, f._id);
      }
    }
    if (b) {if (!f._controlFocus) f._controlFocus = o;}
      else $common.setVisible(o.parentNode.parentNode.parentNode, false);
  }
}
function setForm&Controller;DetailDefaultValue(f) {
  if (f._action == 'New') {
    f.setItemValue('ma_ck', f.grid._discountCode);
    f.setItemValue('ngay_hl', new Date());
  }
  f._setReadOnly(f.getItem('dvt'), !f.getItemValue('nhieu_dvt'));
}
function activeForm&Controller;Detail(f) {
  f.add_onResponseComplete(on$Form&Controller;Detail$ResponseComplete);
  var g = f.grid, a = g._discountType.split(',');
  if (a.length == 0) return;
  var t = a[0], r = a[1];
  f._controlFocus = null;

  setObjectForm&Controller;Hidden(f, 'ma_kho', true, t, 'S');
  setObjectForm&Controller;Hidden(f, 'ma_kh', true, t, 'C');
  setObjectForm&Controller;Hidden(f, 'nh_kh1', true, t, 'D');
  setObjectForm&Controller;Hidden(f, 'nh_kh2', true, t, 'E');
  setObjectForm&Controller;Hidden(f, 'nh_kh3', true, t, 'F');
  setObjectForm&Controller;Hidden(f, 'nh_kh9', true, t, 'G');
  setObjectForm&Controller;Hidden(f, 'ma_vt', true, t, 'I');
  setObjectForm&Controller;Hidden(f, 'dvt', true, t, 'I');
  setObjectForm&Controller;Hidden(f, 'so_luong', null, t, 'I');
  setObjectForm&Controller;Hidden(f, 'nh_vt1', true, t, 'X');
  setObjectForm&Controller;Hidden(f, 'nh_vt2', true, t, 'Y');
  setObjectForm&Controller;Hidden(f, 'nh_vt3', true, t, 'Z');
  setObjectForm&Controller;Hidden(f, 'nh_vt9', true, t, 'T');
  setObjectForm&Controller;Hidden(f, 'tl_ck', null, r, '0');
  setObjectForm&Controller;Hidden(f, 'tien_ck', null, r, '1');
  setObjectForm&Controller;Hidden(f, 'ma_nt', true, r, '1');
  setForm&Controller;DetailDefaultValue(f);
}
function closeForm&Controller;Detail(f) {
  try {f.remove_onResponseComplete(on$Form&Controller;Detail$ResponseComplete);} catch (ex) {}
}
function onChange$&Controller;Detail$Item(o) {
  var f = o.parentForm;
  f.setReferenceKeyFilter('dvt');
  f.request('Item', 'Item', ['ma_vt'], o);
}
function on$Form&Controller;Detail$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      break;
    case 'Scattering':
      setForm&Controller;DetailDefaultValue(f);
      break;
    case 'Item':
      f.setItemControlBehavior('dvt', result[0].Value, result[1].Value, true);
      f.setItemValue('nhieu_dvt', result[2].Value);
      f._setReadOnly(f.getItem('dvt'), !f.getItemValue('nhieu_dvt'));
      break;
    default:
      break;
  }
}
